// 1. 기간 설정: 2026년 7월 1~14일 vs 6월 1~14일
const jul_start = '2026-07-01';
const jul_end = '2026-07-15'; // [시작 이상, 끝 미만)
const jun_start = '2026-06-01';
const jun_end = '2026-06-15';

// 2. 신규 고객 추이
const new_clients_jul = sql(`
  SELECT COUNT(*) as cnt FROM m_client 
  WHERE activation_date >= '${jul_start}' AND activation_date < '${jul_end}'
`);
const new_clients_jun = sql(`
  SELECT COUNT(*) as cnt FROM m_client 
  WHERE activation_date >= '${jun_start}' AND activation_date < '${jun_end}'
`);

// 3. 활성 고객수
const active_clients = sql(`
  SELECT COUNT(*) as cnt FROM m_client WHERE status_enum = 300
`);

// 4. 신규 대출 실행 건수 및 금액
const new_loans_jul = sql(`
  SELECT COUNT(*) as cnt, COALESCE(SUM(principal_amount), 0) as amt 
  FROM m_loan 
  WHERE disbursedon_date >= '${jul_start}' AND disbursedon_date < '${jul_end}'
    AND loan_status_id IN (300, 600, 601, 700)
`);
const new_loans_jun = sql(`
  SELECT COUNT(*) as cnt, COALESCE(SUM(principal_amount), 0) as amt 
  FROM m_loan 
  WHERE disbursedon_date >= '${jun_start}' AND disbursedon_date < '${jun_end}'
    AND loan_status_id IN (300, 600, 601, 700)
`);

// 5. 대출연체율 (현재 상태 기준)
const dlnq_rate = sql(`
  SELECT 
    COUNT(DISTINCT CASE WHEN EXISTS(
      SELECT 1 FROM m_loan_repayment_schedule rs 
      WHERE rs.loan_id = ml.id AND rs.completed_derived = 0 
        AND rs.duedate < CURDATE()
    ) THEN ml.id END) as dlnq_loans,
    COUNT(DISTINCT CASE WHEN ml.loan_status_id IN (300, 600, 601, 700) 
      THEN ml.id END) as total_active
  FROM m_loan ml
`);

// 6. 상각률
const writeoff_rate = sql(`
  SELECT 
    COUNT(CASE WHEN loan_status_id = 601 THEN 1 END) as writeoff_cnt,
    COUNT(CASE WHEN loan_status_id IN (300, 600, 601, 700) THEN 1 END) as total_executed
  FROM m_loan
`);

// 7. 평균 금리 (활성 대출)
const avg_rate = sql(`
  SELECT ROUND(AVG(annual_nominal_interest_rate), 2) as avg_rate
  FROM m_loan WHERE loan_status_id = 300
`);

// 8. 저축 예치 총액
const savings_dep_jul = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_savings_account_transaction 
  WHERE transaction_date >= '${jul_start}' AND transaction_date < '${jul_end}'
    AND transaction_type_enum = 1 AND is_reversed = 0
`);
const savings_dep_jun = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_savings_account_transaction 
  WHERE transaction_date >= '${jun_start}' AND transaction_date < '${jun_end}'
    AND transaction_type_enum = 1 AND is_reversed = 0
`);

// 9. 수수료 부과 총액
const charges_jul = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_loan_charge 
  WHERE createdby_date >= '${jul_start}' AND createdby_date < '${jul_end}'
    AND is_active = 1
`);
const charges_jun = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_loan_charge 
  WHERE createdby_date >= '${jun_start}' AND createdby_date < '${jun_end}'
    AND is_active = 1
`);

