log(`6월(1~14일): ${new_clients_jun[0]?.cnt || 0}명`);

log('\n=== 활성 고객수 ===');
log(`현재 활성 고객: ${active_clients[0]?.cnt || 0}명`);

log('\n=== 신규 대출 실행 ===');
log(`7월(1~14일): ${new_loans_jul[0]?.cnt || 0}건, ${new_loans_jul[0]?.amt || 0}원`);
