  ? ((writeoff_cnt / total_executed) * 100).toFixed(2)
  : 0;
log(`상각률: ${writeoff_pct}%`);

log('\n=== 평균 금리 ===');
log(`활성 대출 평균금리: ${avg_rate[0]?.avg_rate || 0}%`);

log('\n=== 저축 예치 ===');
log(`7월: ${savings_dep_jul[0]?.amt || 0}원, 6월: ${savings_dep_jun[0]?.amt || 0}원`);
const sav_diff = (savings_dep_jul[0]?.amt || 0) - (savings_dep_jun[0]?.amt || 0);
log(`변화: ${sav_diff > 0 ? '+' : ''}${sav_diff}원`);

log('\n=== 수수료 부과 ===');
log(`7월: ${charges_jul[0]?.amt || 0}원, 6월: ${charges_jun[0]?.amt || 0}원`);
const charge_diff = (charges_jul[0]?.amt || 0) - (charges_jun[0]?.amt || 0);
log(`변화: ${charge_diff > 0 ? '+' : ''}${charge_diff}원`);

log('\n=== 요약 ===');
log(`✓ 신규 고객: ${client_diff > 0 ? '증가' : client_diff < 0 ? '감소' : '동일'}`);
log(`✓ 신규 대출: ${loan_cnt_diff > 0 ? '증가' : loan_cnt_diff < 0 ? '감소' : '동일'}`);
log(`✓ 포트폴리오: 연체율 ${dlnq_pct}%, 상각률 ${writeoff_pct}%`);
log(`✓ 저축: ${sav_diff > 0 ? '증가' : sav_diff < 0 ? '감소' : '동일'}`);
log(`✓ 수수료: ${charge_diff > 0 ? '증가' : charge_diff < 0 ? '감소' : '동일'}`);

// 1. 기간 설정: 2026년 7월 1~14일 vs 6월 1~14일
const jul_start = '2026-07-01';
const jul_end = '2026-07-15';
const jun_start = '2026-06-01';
const jun_end = '2026-06-15';
const today = '2026-07-14';

// 2. 신규 고객 추이
const new_clients_jul = sql(`
  SELECT COUNT(*) as cnt FROM m_client 
  WHERE activation_date >= '${jul_start}' AND activation_date < '${jul_end}'
`);
const new_clients_jun = sql(`
  SELECT COUNT(*) as cnt FROM m_client 
  WHERE activation_date >= '${jun_start}' AND activation_date < '${jun_end}'
`);

// 3. 활성 고객수
const active_clients = sql(`
  SELECT COUNT(*) as cnt FROM m_client WHERE status_enum = 300
`);

// 4. 신규 대출 실행 건수 및 금액
const new_loans_jul = sql(`
  SELECT COUNT(*) as cnt, COALESCE(SUM(principal_amount), 0) as amt 
  FROM m_loan 
  WHERE disbursedon_date >= '${jul_start}' AND disbursedon_date < '${jul_end}'
    AND loan_status_id IN (300, 600, 601, 700)
`);
const new_loans_jun = sql(`
  SELECT COUNT(*) as cnt, COALESCE(SUM(principal_amount), 0) as amt 
  FROM m_loan 
  WHERE disbursedon_date >= '${jun_start}' AND disbursedon_date < '${jun_end}'
    AND loan_status_id IN (300, 600, 601, 700)
`);

// 5. 대출연체율 (현재 상태 기준)
const dlnq_rate = sql(`
  SELECT 
    COUNT(DISTINCT ml.id) as total_active,
    COUNT(DISTINCT CASE 
      WHEN EXISTS(
        SELECT 1 FROM m_loan_repayment_schedule rs 
        WHERE rs.loan_id = ml.id AND rs.completed_derived = 0 
          AND rs.duedate < '${today}'
      ) THEN ml.id 
    END) as dlnq_loans
  FROM m_loan ml
  WHERE ml.loan_status_id IN (300, 600, 601, 700)
`);

// 6. 상각률
const writeoff_rate = sql(`
  SELECT 
    COUNT(CASE WHEN loan_status_id = 601 THEN 1 END) as writeoff_cnt,
    COUNT(CASE WHEN loan_status_id IN (300, 600, 601, 700) THEN 1 END) as total_executed
  FROM m_loan
`);

// 7. 평균 금리 (활성 대출)
const avg_rate = sql(`
  SELECT ROUND(AVG(annual_nominal_interest_rate), 2) as avg_rate
  FROM m_loan WHERE loan_status_id = 300
`);

// 8. 저축 예치 총액
const savings_dep_jul = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_savings_account_transaction 
  WHERE transaction_date >= '${jul_start}' AND transaction_date < '${jul_end}'
    AND transaction_type_enum = 1 AND is_reversed = 0
`);
const savings_dep_jun = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_savings_account_transaction 
  WHERE transaction_date >= '${jun_start}' AND transaction_date < '${jun_end}'
    AND transaction_type_enum = 1 AND is_reversed = 0
`);

// 9. 수수료 부과 총액 (is_active 필터 활용)
const charges_jul = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_loan_charge 
  WHERE id > 0 AND is_active = 1
`);
const charges_jun = sql(`
  SELECT COALESCE(SUM(amount), 0) as amt FROM m_loan_charge 
  WHERE id > 0 AND is_active = 1
`);

// 로그 출력
log('=== 기간 설정 ===');
log(`7월(1~14일): ${jul_start} ~ ${jul_end}, 6월(1~14일): ${jun_start} ~ ${jun_end}`);

log('\n=== 신규 고객 ===');
log(`7월: ${new_clients_jul[0]?.cnt || 0}명, 6월: ${new_clients_jun[0]?.cnt || 0}명`);
const client_diff = (new_clients_jul[0]?.cnt || 0) - (new_clients_jun[0]?.cnt || 0);
log(`변화: ${client_diff > 0 ? '+' : ''}${client_diff}명 (${client_diff >= 0 ? '증가' : '감소'})`);

log('\n=== 활성 고객수 (현재) ===');
log(`${active_clients[0]?.cnt || 0}명`);

log('\n=== 신규 대출 실행 ===');
log(`7월: ${new_loans_jul[0]?.cnt || 0}건, ${new_loans_jul[0]?.amt || 0}원`);
log(`6월: ${new_loans_jun[0]?.cnt || 0}건, ${new_loans_jun[0]?.amt || 0}원`);
const loan_cnt_diff = (new_loans_jul[0]?.cnt || 0) - (new_loans_jun[0]?.cnt || 0);
const loan_amt_diff = (new_loans_jul[0]?.amt || 0) - (new_loans_jun[0]?.amt || 0);
log(`건수 변화: ${loan_cnt_diff > 0 ? '+' : ''}${loan_cnt_diff}건, 금액 변화: ${loan_amt_diff > 0 ? '+' : ''}${loan_amt_diff}원`);

log('\n=== 대출 포트폴리오 건강도 ===');
const total_active = dlnq_rate[0]?.total_active || 0;
const dlnq_loans = dlnq_rate[0]?.dlnq_loans || 0;
log(`실행 대출: ${total_active}건, 연체 대출: ${dlnq_loans}건`);
const dlnq_pct = total_active > 0 
  ? ((dlnq_loans / total_active) * 100).toFixed(2)
  : 0;
log(`연체율: ${dlnq_pct}%`);

const writeoff_cnt = writeoff_rate[0]?.writeoff_cnt || 0;
const total_executed = writeoff_rate[0]?.total_executed || 0;
log(`상각 대출: ${writeoff_cnt}건 / 실행 대출: ${total_executed}건`);
const writeoff_pct = total_executed > 0
  ? ((writeoff_cnt / total_executed) * 100).toFixed(2)
  : 0;
log(`상각률: ${writeoff_pct}%`);

log('\n=== 평균 금리 ===');
log(`활성 대출 평균금리: ${avg_rate[0]?.avg_rate || 0}%`);

log('\n=== 저축 예치 ===');
log(`7월: ${savings_dep_jul[0]?.amt || 0}원, 6월: ${savings_dep_jun[0]?.amt || 0}원`);
const sav_diff = (savings_dep_jul[0]?.amt || 0) - (savings_dep_jun[0]?.amt || 0);
log(`변화: ${sav_diff > 0 ? '+' : ''}${sav_diff}원 (${sav_diff >= 0 ? '증가' : '감소'})`);

log('\n=== 활성 수수료 부과 (현재 활성) ===');
log(`활성 수수료 누적: ${charges_jul[0]?.amt || 0}원`);

log('\n=== 경영 하이라이트 요약 ===');
log(`✓ 신규 고객 ${client_diff >= 0 ? '증가' : '감소'} (${Math.abs(client_diff)}명)`);
log(`✓ 신규 대출 ${loan_cnt_diff >= 0 ? '증가' : '감소'} (${Math.abs(loan_cnt_diff)}건)`);
log(`✓ 포트폴리오: 연체율 ${dlnq_pct}%, 상각률 ${writeoff_pct}%`);
log(`✓ 활성 고객 규모: ${active_clients[0]?.cnt || 0}명`);
log(`✓ 평균 금리: ${avg_rate[0]?.avg_rate || 0}%`);

