SELECT o.name AS office_name, COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END) AS executed_loans, COUNT(DISTINCT CASE WHEN lrs.duedate < CAST('2026-07-14' AS DATE) AND lrs.completed_derived = 0 THEN l.id END) AS delinquent_loans, ROUND(100.0 * COUNT(DISTINCT CASE WHEN lrs.duedate < CAST('2026-07-14' AS DATE) AND lrs.completed_derived = 0 THEN l.id END) / NULLIF(COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END), 0), 2) AS dlnq_rate_pct FROM m_office o LEFT JOIN m_client c ON c.office_id = o.id LEFT JOIN m_loan l ON l.client_id = c.id LEFT JOIN m_loan_repayment_schedule lrs ON lrs.loan_id = l.id WHERE o.id != 1 GROUP BY o.id, o.name ORDER BY dlnq_rate_pct DESC;
SELECT o.name AS office_name, COUNT(DISTINCT CASE WHEN l.loan_status_id = 601 THEN l.id END) AS writeoff_loans, COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END) AS executed_loans, ROUND(100.0 * COUNT(DISTINCT CASE WHEN l.loan_status_id = 601 THEN l.id END) / NULLIF(COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END), 0), 2) AS writeoff_rate_pct FROM m_office o LEFT JOIN m_client c ON c.office_id = o.id LEFT JOIN m_loan l ON l.client_id = c.id WHERE o.id != 1 GROUP BY o.id, o.name ORDER BY writeoff_rate_pct DESC;
SELECT o.name AS office_name, COUNT(DISTINCT CASE WHEN l.loan_status_id NOT IN (100, 500) THEN l.id END) AS completed_review_loans, COUNT(DISTINCT CASE WHEN l.loan_status_id NOT IN (100, 500) AND l.loan_status_id IN (300, 600, 601, 700) THEN l.id END) AS approved_loans, ROUND(100.0 * COUNT(DISTINCT CASE WHEN l.loan_status_id NOT IN (100, 500) AND l.loan_status_id IN (300, 600, 601, 700) THEN l.id END) / NULLIF(COUNT(DISTINCT CASE WHEN l.loan_status_id NOT IN (100, 500) THEN l.id END), 0), 2) AS approval_rate_pct FROM m_office o LEFT JOIN m_client c ON c.office_id = o.id LEFT JOIN m_loan l ON l.client_id = c.id WHERE o.id != 1 GROUP BY o.id, o.name ORDER BY approval_rate_pct ASC

SELECT o.name AS office_name, COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END) AS executed_loans, COUNT(DISTINCT CASE WHEN lrs.duedate < CAST('2026-07-14' AS DATE) AND lrs.completed_derived = 0 THEN l.id END) AS delinquent_loans, ROUND(100.0 * COUNT(DISTINCT CASE WHEN lrs.duedate < CAST('2026-07-14' AS DATE) AND lrs.completed_derived = 0 THEN l.id END) / NULLIF(COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END), 0), 2) AS dlnq_rate_pct FROM m_office o LEFT JOIN m_client c ON c.office_id = o.id LEFT JOIN m_loan l ON l.client_id = c.id LEFT JOIN m_loan_repayment_schedule lrs ON lrs.loan_id = l.id WHERE o.id != 1 GROUP BY o.id, o.name ORDER BY dlnq_rate_pct DESC;
SELECT o.name AS office_name, COUNT(DISTINCT CASE WHEN l.loan_status_id = 601 THEN l.id END) AS writeoff_loans, COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END) AS executed_loans, ROUND(100.0 * COUNT(DISTINCT CASE WHEN l.loan_status_id = 601 THEN l.id END) / NULLIF(COUNT(DISTINCT CASE WHEN l.loan_status_id IN (300, 600, 601, 700) THEN l.id END), 0), 2) AS writeoff_rate_pct FROM m_office o LEFT JOIN m_client c ON c.office_id = o.id LEFT JOIN m_loan l ON l.client_id = c.id WHERE o.id != 1 GROUP BY o.id, o.name ORDER BY writeoff_rate_pct DESC;
